#include<bits/stdc++.h>
using namespace std;
char a[11][11], b[11][11], c[11][11];
int n;
bool z90(char a[11][11], char c[11][11], int n) {
	for (int i = 0; i < n; i++) {
		for (int j = 0; j < n; j++) {
			if (a[i][j] != c[j][n - 1 - i]) {
				return false;
			}
		}
	}
	return true;
}
bool z180(char a[11][11], char c[11][11], int n) {
	for (int i = 0; i < n; i++) {
		for (int j = 0; j < n; j++) {
			if (a[i][j] != c[n - 1 - i][n - 1 - j]) {
				return false;
			}
		}
	}
	return true;
}
bool z270(char a[11][11], char c[11][11], int n) {
	for (int i = 0; i < n; i++) {
		for (int j = 0; j < n; j++) {
			if (a[j][n - 1 - i] != c[i][j]) {
				return false;
			}
		}
	}
	return true;

}
bool fan(char a[11][11], char c[11][11], int n) {
	for (int i = 0; i < n; i++) {
		for (int j = 0; j < n; j++) {
			if (a[i][j] != c[i][n - 1 - j]) {
				return false;
			}
		}
	}
	return true;

}
bool zu(char a[11][11], char c[11][11], int n) {
	for (int i = 0; i < n; i++) {
		for (int j = 0; j < n; j++) {
			b[i][j] = a[i][n - 1 - j];
		}
	}
	if(z90(b,c,n)||z180(b,c,n)||z270(b,c,n))return true;
	return false;
}bool bu(char a[11][11], char c[11][11], int n) {
	for (int i = 0; i < n; i++) {
		for (int j = 0; j < n; j++) {
			if (a[i][j] != c[i][j]) {
				return false;
			}
		}
	}
	return true;

}
int main() {
	cin >> n;
	for (int i = 0; i < n; i++) {
		for (int j = 0; j < n; j++) {
			char c1;
			cin >> c1;
			a[i][j] = c1;
		}
	}
	for (int i = 0; i < n; i++) {
		for (int j = 0; j < n; j++) {
			char c1;
			cin >> c1;
			c[i][j] = c1;
		}
	}
	if (z90(a, c, n)) {
		cout << "1";
	} else if (z180(a, c, n)) {
		cout << "2";
	} else if (z270(a, c, n)) {
		cout << "3";
	} else if (fan(a, c, n)) {
		cout << "4";
	} else if (zu(a, c, n)){
		cout<<"5";}
	else if(bu(a, c, n)){
		cout<<"6";
	}else{
		cout<<"7";
	}return 0;
}
